<template><el-card><template #header><div class="head"><b>流动人口当前与历史登记</b><el-button v-if="user.hasPermission('floating:create')" type="primary" @click="$router.push('/floating-registrations/applications/create')">新建登记申请</el-button></div></template><el-form inline><el-form-item label="登记号"><el-input v-model="q.registrationNo" clearable/></el-form-item><el-form-item label="姓名"><el-input v-model="q.personName" clearable/></el-form-item><el-form-item label="状态"><el-select v-model="q.status" clearable><el-option v-for="x in ['ACTIVE','LEFT','CANCELLED','EXPIRED']" :key="x" :value="x"/></el-select></el-form-item><el-button @click="load">查询</el-button></el-form><el-table :data="rows"><el-table-column prop="registrationNo" label="登记号"/><el-table-column prop="personName" label="姓名"/><el-table-column prop="identityNo" label="身份证号"/><el-table-column prop="currentAddress" label="当前地址"/><el-table-column prop="eligibleFromDate" label="可申领日期"/><el-table-column prop="status" label="状态"/><el-table-column label="操作"><template #default="{row}"><el-button link @click="$router.push('/floating-populations/'+row.floatingId)">详情</el-button></template></el-table-column></el-table></el-card></template>
<script setup>import{reactive,ref,onMounted}from'vue';import{getFloatingPopulations}from'../../api/floatingResidence';import{useUserStore}from'../../stores/user';const user=useUserStore(),q=reactive({registrationNo:'',personName:'',status:'',page:0,size:20}),rows=ref([]);async function load(){const r=await getFloatingPopulations(q);rows.value=r.content||[]}onMounted(load)</script><style scoped>.head{display:flex;justify-content:space-between}</style>
